import{_ as t,o as i,c as a,ai as r}from"./chunks/framework.CaiDwmc7.js";const u=JSON.parse('{"title":"VS Code Extension Overview","description":"The Prism VS Code Extension — sidebar chat, Spectrum execution, native tree views, Office visualization, and plugin skill routing.","frontmatter":{"title":"VS Code Extension Overview","description":"The Prism VS Code Extension — sidebar chat, Spectrum execution, native tree views, Office visualization, and plugin skill routing.","outline":[2,3]},"headers":[],"relativePath":"vscode/index.md","filePath":"vscode/index.md","lastUpdated":0}'),o={name:"vscode/index.md"};function n(s,e,d,l,c,h){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="vs-code-extension-overview" tabindex="-1">VS Code Extension Overview <a class="header-anchor" href="#vs-code-extension-overview" aria-label="Permalink to “VS Code Extension Overview”">​</a></h1><p>The Prism VS Code Extension (<code>cmd/prism-vscode/</code>) brings the full 4-phase workflow directly into the IDE. It provides a sidebar chat interface, tree views for research/plans/stories, Spectrum autonomous execution, an Office pixel-art visualization, a Monitor dashboard, and Workspaces management — all without leaving VS Code.</p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to “Key Features”">​</a></h2><ul><li><strong>Sidebar chat</strong>: Interactive Claude chat with streaming tool visualization, phase-aware system prompts</li><li><strong>Spectrum execution</strong>: Autonomous story execution with real-time progress, logs, and signal handling</li><li><strong>Native tree views</strong>: Research, Plans, and Stories tree providers in the activity bar with context menus</li><li><strong>Bottom panel</strong>: Three-view system (Monitor, Office, Workspaces) in a unified panel</li><li><strong>Office visualization</strong>: Pixel-art office with animated agent characters, furniture placement editor</li><li><strong>Plugin skill routing</strong>: Seamless bridging between SDK chat and CLI plugin skills (<code>/prism-research</code>, <code>/prism-plan</code>, etc.)</li><li><strong>Workflow state machine</strong>: Validated phase transitions (Idle → Research → Plan → Implement → Validate)</li><li><strong>Status bar integration</strong>: Workflow phase, story progress, and Spectrum status indicators</li><li><strong>33 commands</strong>: Workflow phases, Spectrum control, tree operations, Office/Monitor actions</li><li><strong>7 configurable settings</strong>: Model selection, Spectrum parameters, auto-approval options</li></ul><h2 id="extension-metadata" tabindex="-1">Extension Metadata <a class="header-anchor" href="#extension-metadata" aria-label="Permalink to “Extension Metadata”">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Name</td><td>Prism</td></tr><tr><td>Version</td><td>2.3.0</td></tr><tr><td>Publisher</td><td>prism</td></tr><tr><td>Categories</td><td>AI, Programming Languages, Other</td></tr><tr><td>Min VS Code</td><td>1.84.0</td></tr><tr><td>Activation</td><td><code>onView:prism.sidebar</code>, <code>onStartupFinished</code></td></tr><tr><td>Entry Point</td><td><code>./dist/extension.js</code></td></tr></tbody></table>',6)])])}const m=t(o,[["render",n]]);export{u as __pageData,m as default};
